/*
 * Page Replacement and Working Set Tracking
 * Demonstrates local replacement to prevent thrashing
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <time.h>

#define MAX_PAGES 100
#define MAX_FRAMES 50
#define TIME_WINDOW 10

typedef struct {
 int page_id;
 int last_reference_time;
} PageEntry;

typedef struct {
 int pid;
 int allocated_frames;
 int working_set_size;
 PageEntry frames[MAX_FRAMES];
 int frame_count;
 int page_faults;
 int references[TIME_WINDOW]; // Recent page references
 int ref_index;
} Process;

// Initialize process
void init_process(Process *p, int pid, int frames) {
 p->pid = pid;
 p->allocated_frames = frames;
 p->working_set_size = 0;
 p->frame_count = 0;
 p->page_faults = 0;
 p->ref_index = 0;

 for (int i = 0; i < TIME_WINDOW; i++) {
 p->references[i] = -1;
 }
}

// Add reference to process
void add_reference(Process *p, int page) {
 p->references[p->ref_index] = page;
 p->ref_index = (p->ref_index + 1) % TIME_WINDOW;
}

// Calculate working set size (unique pages in time window)
int calculate_working_set(Process *p) {
 bool seen[MAX_PAGES] = {false};
 int count = 0;

 for (int i = 0; i < TIME_WINDOW; i++) {
 int page = p->references[i];
 if (page >= 0 && !seen[page]) {
 seen[page] = true;
 count++;
 }
 }

 p->working_set_size = count;
 return count;
}

// Check if page is in memory (local replacement)
bool page_in_memory(Process *p, int page) {
 for (int i = 0; i < p->frame_count; i++) {
 if (p->frames[i].page_id == page) {
 return true;
 }
 }
 return false;
}

// Handle page fault with local LRU replacement
void handle_page_fault(Process *p, int page, int current_time) {
 p->page_faults++;

 // If we have free frames, add directly
 if (p->frame_count < p->allocated_frames) {
 p->frames[p->frame_count].page_id = page;
 p->frames[p->frame_count].last_reference_time = current_time;
 p->frame_count++;
 } else {
 // Local LRU replacement - only replace from THIS process
 int lru_index = 0;
 int oldest_time = p->frames[0].last_reference_time;

 for (int i = 1; i < p->frame_count; i++) {
 if (p->frames[i].last_reference_time < oldest_time) {
 oldest_time = p->frames[i].last_reference_time;
 lru_index = i;
 }
 }

 // Replace LRU page (LOCAL - doesn't affect other processes)
 printf(" Process %d: LRU replace page %d with page %d (LOCAL)\n",
 p->pid, p->frames[lru_index].page_id, page);
 p->frames[lru_index].page_id = page;
 p->frames[lru_index].last_reference_time = current_time;
 }
}

// Check for thrashing condition
bool is_thrashing(Process *processes, int num_procs, int threshold) {
 int total_faults = 0;
 for (int i = 0; i < num_procs; i++) {
 total_faults += processes[i].page_faults;
 }
 return total_faults > threshold;
}

// Working Set Model: Check if process can be admitted
bool can_admit_process(Process *processes, int num_procs, int required_ws, 
 int total_available_frames) {
 int total_ws = 0;
 for (int i = 0; i < num_procs; i++) {
 total_ws += processes[i].working_set_size;
 }

 return (total_ws + required_ws) <= total_available_frames;
}

int main() {
 printf("=== Working Set & Local Replacement Demo ===\n\n");

 Process processes[4];
 int total_frames = 100;

 // Initialize processes with different working set requirements
 init_process(&processes[0], 1, 40); // Video editor
 init_process(&processes[1], 2, 25); // Compiler
 init_process(&processes[2], 3, 20); // Browser
 init_process(&processes[3], 4, 30); // New app

 int num_procs = 2; // Start with 2 processes

 printf("Initial state: %d processes running\n", num_procs);
 printf("Total frames: %d\n\n", total_frames);

 // Simulate page references
 srand(42);
 int current_time = 0;

 printf("--- Adding process references ---\n");
 for (int i = 0; i < 20; i++) {
 for (int p = 0; p < num_procs; p++) {
 // Simulate locality: 70% working set, 30% new page
 int page;
 if (rand() % 100 < 70 && processes[p].working_set_size > 0) {
 // Reference from working set (simplified)
 page = rand() % processes[p].working_set_size;
 } else {
 page = rand() % 50; // New page
 }

 add_reference(&processes[p], page);

 if (!page_in_memory(&processes[p], page)) {
 handle_page_fault(&processes[p], page, current_time);
 }

 // Recalculate working set periodically
 if (i % 5 == 0) {
 calculate_working_set(&processes[p]);
 }
 }
 current_time++;
 }

 printf("\n--- Working Set Analysis ---\n");
 int total_ws = 0;
 for (int i = 0; i < num_procs; i++) {
 calculate_working_set(&processes[i]);
 printf("Process %d: working set = %d frames, allocated = %d, faults = %d\n",
 processes[i].pid, processes[i].working_set_size, 
 processes[i].allocated_frames, processes[i].page_faults);
 total_ws += processes[i].working_set_size;
 }

 printf("\nTotal working set demand: %d frames\n", total_ws);
 printf("Available frames: %d\n", total_frames);

 if (total_ws <= total_frames) {
 printf("Status: ✓ STABLE - Working sets fit in memory\n");
 } else {
 printf("Status: ⚠ OVER-COMMITTED - Thrashing risk!\n");
 }

 // Demonstrate adding new process
 printf("\n--- Attempting to add Process 4 (needs 30 frames) ---\n");
 if (can_admit_process(processes, num_procs, 30, total_frames)) {
 printf("Process 4 ADMITTED - Working set model allows it\n");
 } else {
 printf("Process 4 REJECTED - Would cause thrashing!\n");
 printf("Solution: Suspend/swap out existing process\n");
 }

 return 0;
}
